def get_name(location: str) -> str:
    city = location
    if "Japan" in city or "Tokyo" in city or "Osaka" in city or "Kyoto" in city:
        pool = NAMES["Japan"]
    elif "Korea" in city or "Seoul" in city or "Busan" in city:
        pool = NAMES["Korea"]
    elif "China" in city or "Hong Kong" in city or "Taiwan" in city or "Singapore" in city or "Beijing" in city or "Shanghai" in city or "Shenzhen" in city or "Guangzhou" in city or "Chengdu" in city:
        pool = NAMES["China"]
    elif "Thailand" in city or "Malaysia" in city or "Philippines" in city or "Indonesia" in city or "Vietnam" in city:
        pool = NAMES["SoutheastAsia"]
    elif "India" in city or "Mumbai" in city or "Delhi" in city or "Bangalore" in city or "Chennai" in city or "Hyderabad" in city or "Bangladesh" in city or "Sri Lanka" in city or "Pakistan" in city:
        pool = NAMES["India"]
    elif "Egypt" in city or "Kenya" in city or "Nigeria" in city or "South Africa" in city or "Ghana" in city:
        pool = NAMES["Africa"]
    elif "UAE" in city or "Saudi" in city or "Israel" in city or "Turkey" in city or "Dubai" in city or "Riyadh" in city or "Tel Aviv" in city or "Istanbul" in city:
        pool = NAMES["MiddleEast"]
    elif "Mexico" in city or "Brazil" in city or "Argentina" in city or "Peru" in city or "Colombia" in city or "Chile" in city:
        pool = NAMES["LatAm"]
    elif "France" in city or "Paris" in city or "Lyon" in city:
        pool = NAMES["France"]
    elif "Germany" in city or "Berlin" in city or "Munich" in city or "Hamburg" in city:
        pool = NAMES["Germany"]
    elif "Spain" in city or "Madrid" in city or "Barcelona" in city:
        pool = NAMES["Spain"]
    elif "Italy" in city or "Rome" in city or "Milan" in city:
        pool = NAMES["Italy"]
    elif "UK" in city or "London" in city or "Manchester" in city or "Birmingham" in city:
        pool = NAMES["UK"]
    elif "Canada" in city or "Toronto" in city or "Vancouver" in city or "Montreal" in city or "Calgary" in city or "Ottawa" in city:
        pool = NAMES["Canada"]
    elif "Australia" in city or "Sydney" in city or "Melbourne" in city or "Brisbane" in city or "Perth" in city or "New Zealand" in city or "Auckland" in city:
        pool = NAMES["Australia"]
    elif "Netherlands" in city or "Austria" in city or "Switzerland" in city or "Amsterdam" in city or "Vienna" in city or "Zurich" in city:
        pool = NAMES["Germany"]
    else:
        pool = NAMES["USA"]
    return random.choice(pool)

