def get_nearby(location: str) -> str:
    city = location.split(",")[0] + ", " + location.split(",")[1].strip()
    for key, vals in NEARBY.items():
        if key.startswith(location.split(",")[0]):
            return random.choice(vals)
    # fallback: return same city
    return location

